proof_block:
// Bind the two `forall` bodies into shared spec values so the SMT lambdas
// representing the postcondition's r1- and r2-quantifiers can collapse to
// a single term — closing the alpha-equivalence / trigger gap that left
// z3 returning `unknown` on `r1.0 == r2.0`.
let p: bool = forall |i: int| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@;
let q: bool = self_.vals@[hi as int]@ != v@
    && (forall |i: int| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@);

// Reflexive: the let-bound `p` is the same proposition as the forall
// occurring verbatim in the postcondition. Mentioning both forms here
// ensures z3 unifies the lambda from the let-binding with the lambda
// produced by the postcondition's verbatim forall.
assert(p == (forall |i: int| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@));
assert(q == (self_.vals@[hi as int]@ != v@
    && (forall |i: int| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@)));

// Propositional tautology: when both runs bind their `.0` to `p`,
// they agree.
assert((r1.0 == p) && (r2.0 == p) ==> r1.0 == r2.0);

// Propositional tautology: in the `!r1.0` branch (equivalently `!r2.0`
// by the previous step), both runs bind their `.1` to `q`, so they
// agree.
assert(
    (!r1.0 ==> r1.1 == q)
    && (!r2.0 ==> r2.1 == q)
    && (r1.0 == r2.0)
    ==> (!r1.0 ==> r1.1 == r2.1)
);

// Chain the two tautologies into the full postcondition shape, using
// `p` and `q` as the shared SMT terms so z3 can match them against
// the postcondition's quantifiers.
assert(
    (r1.0 == p) && (r2.0 == p)
    && (!r1.0 ==> r1.1 == q) && (!r2.0 ==> r2.1 == q)
    ==> ((r1.0 == r2.0) && (!r1.0 ==> r1.1 == r2.1))
);
